import React, { useEffect, useState, useMemo } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  PiggyBank, AlertCircle, ArrowUpCircle, Target, 
  CreditCard, Calendar, TrendingUp, X, ArrowDownCircle
} from 'lucide-react';
import '../styles/Orcamento.css';

const Orcamento = () => {
  const [loading, setLoading] = useState(true);
  const [modalDetalhe, setModalDetalhe] = useState({ aberto: false, tipo: '', dados: [] });
  const [dados, setDados] = useState({
    metaReceita: 0,
    receitaReal: 0,
    metaGasto: 0,
    gastoReal: 0,
    gastoCartao: 0,
    gastoVariavel: 0,
    categoriasDespesa: [],
    objetivosPessoais: [],
    proventosDetalhados: [],
    resumo503020: {
      essenciais: { valor: 0, limite: 0 },
      estiloVida: { valor: 0, limite: 0 },
      prioridades: { valor: 0, limite: 0 }
    }
  });

  useEffect(() => {
    buscarDadosCompletos();
  }, []);

  const formatMoney = (v) => {
    return (Number(v) || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  async function buscarDadosCompletos() {
    setLoading(true);
    try {
      const agora = new Date();
      const ano = agora.getFullYear();
      const mes = agora.getMonth() + 1;
      const primeiroDia = `${ano}-${String(mes).padStart(2, '0')}-01`;
      const ultimoDia = new Date(ano, mes, 0).toISOString().split('T')[0];

      const [
        { data: metasData },
        { data: proventos },
        { data: comprasVariaveis },
        { data: parcelasMes },
        { data: cats }
      ] = await Promise.all([
        supabase.from('metas').select('*').eq('mes_referencia', mes).eq('ano_referencia', ano),
        supabase.from('proventos').select('*').gte('data_recebimento', primeiroDia).lte('data_recebimento', ultimoDia),
        supabase.from('compras').select('valor_total, categoria_id').gte('data_compra', primeiroDia).lte('data_compra', ultimoDia),
        supabase.from('parcelas').select('valor_parcela, compras!inner(categoria_id)').gte('data_vencimento', primeiroDia).lte('data_vencimento', ultimoDia),
        supabase.from('categorias').select('*').order('nome', { ascending: true })
      ]);

      const gastosPorCat = {};
      comprasVariaveis?.forEach(c => gastosPorCat[c.categoria_id] = (gastosPorCat[c.categoria_id] || 0) + Number(c.valor_total));
      parcelasMes?.forEach(p => {
        const catId = p.compras?.categoria_id;
        if (catId) gastosPorCat[catId] = (gastosPorCat[catId] || 0) + Number(p.valor_parcela);
      });

      const todasCategoriasConsolidadas = (cats || []).map(cat => {
        const metaEncontrada = metasData?.find(m => m.categoria_id === cat.id);
        return {
          ...cat,
          gastoReal: Number(gastosPorCat[cat.id] || 0),
          metaValor: metaEncontrada ? Number(metaEncontrada.valor_meta) : 0,
          tipoMeta: metaEncontrada?.tipo_meta || 'despesa',
        };
      });

      const categoriasDespesa = todasCategoriasConsolidadas.filter(c => c.tipo === 'despesa' && c.tipoMeta !== 'pessoal');
      const objetivosPessoais = todasCategoriasConsolidadas.filter(c => c.tipoMeta === 'pessoal');

      const totalReceitaReal = proventos?.reduce((acc, cur) => acc + Number(cur.valor), 0) || 0;
      const totalGastoReal = Object.values(gastosPorCat).reduce((a, b) => a + b, 0);

      const resumo503020 = {
        essenciais: { valor: 0, limite: totalReceitaReal * 0.5 },
        estiloVida: { valor: 0, limite: totalReceitaReal * 0.3 },
        prioridades: { valor: 0, limite: totalReceitaReal * 0.2 }
      };

      const essenciaisLista = ['Aluguel', 'Saúde', 'Educação', 'Mercado', 'Transporte', 'Água', 'Luz', 'Moradia'];

      todasCategoriasConsolidadas.forEach(cat => {
        if (cat.tipoMeta === 'pessoal') resumo503020.prioridades.valor += cat.gastoReal;
        else if (essenciaisLista.some(e => cat.nome.includes(e))) resumo503020.essenciais.valor += cat.gastoReal;
        else if (cat.tipo === 'despesa') resumo503020.estiloVida.valor += cat.gastoReal;
      });

      setDados({
        metaReceita: metasData?.filter(m => m.tipo_meta === 'provento').reduce((a, b) => a + Number(b.valor_meta), 0) || 0,
        receitaReal: totalReceitaReal,
        metaGasto: metasData?.filter(m => m.tipo_meta === 'despesa').reduce((a, b) => a + Number(b.valor_meta), 0) || 0,
        gastoReal: totalGastoReal,
        gastoCartao: parcelasMes?.reduce((acc, cur) => acc + Number(cur.valor_parcela), 0) || 0,
        gastoVariavel: comprasVariaveis?.reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0,
        categoriasDespesa,
        objetivosPessoais,
        proventosDetalhados: proventos || [],
        resumo503020
      });
    } catch (err) { console.error(err); } finally { setLoading(false); }
  }

  const porcGasto = useMemo(() => dados.metaGasto > 0 ? (dados.gastoReal / dados.metaGasto) * 100 : 0, [dados.gastoReal, dados.metaGasto]);
  const porcReceita = useMemo(() => dados.metaReceita > 0 ? (dados.receitaReal / dados.metaReceita) * 100 : 0, [dados.receitaReal, dados.metaReceita]);

  if (loading) return <div className="loading-state">Organizando suas finanças...</div>;

  return (
    <div className="orcamento-container fade-in">
      <header className="orcamento-header">
        <div className="header-info">
          <h2>Gestão Estratégica</h2>
          <div className="badge-mes"><Calendar size={14} /><span>{new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(new Date()).toUpperCase()}</span></div>
        </div>
        <button className="btn-ajuste-premium" onClick={() => window.location.href='/metas'}><Target size={18} /> <span>Metas</span></button>
      </header>

      {/* CARD GLOBAL */}
      <section className="main-stats-card">
        <div className="stats-header">
          <div>
            <span className="stats-label">Uso do Orçamento Mensal</span>
            <div className="stats-values">
              <h3>{formatMoney(dados.gastoReal)}</h3>
              <span className="goal-value">/ {formatMoney(dados.metaGasto)}</span>
            </div>
          </div>
          <div className={`status-icon ${dados.gastoReal > dados.metaGasto ? 'danger' : 'success'}`}><PiggyBank size={32} /></div>
        </div>
        <div className="premium-progress-bg">
          <div className={`premium-progress-fill ${porcGasto > 100 ? 'critical' : ''}`} style={{ width: `${Math.min(porcGasto, 100)}%` }} />
        </div>
        <div className="progress-details">
          <span className="perc-text">{porcGasto.toFixed(1)}% utilizado</span>
          {dados.receitaReal < dados.metaGasto && <span className="deficit-badge"><AlertCircle size={12}/> Orçamento Deficitário</span>}
        </div>
      </section>

      {/* CARDS LADO A LADO (ESTILO OBJETIVOS) */}
      <div className="summary-grid-objectives">
        <div className="objective-card-premium clickable" onClick={() => setModalDetalhe({ aberto: true, tipo: 'Receitas', dados: dados.proventosDetalhados })}>
          <div className="obj-header">
            <span className="obj-name"><ArrowUpCircle size={16} color="#10b981" /> Total Recebido</span>
            <span className="obj-percent" style={{color: '#10b981'}}>{porcReceita.toFixed(0)}%</span>
          </div>
          <div className="obj-progress-container">
            <div className="obj-progress-fill" style={{ width: `${Math.min(porcReceita, 100)}%`, backgroundColor: '#10b981' }} />
          </div>
          <div className="obj-footer">
            <span className="obj-real">{formatMoney(dados.receitaReal)}</span>
            <span className="obj-goal">Meta: {formatMoney(dados.metaReceita)}</span>
          </div>
        </div>

        <div className="objective-card-premium clickable" onClick={() => setModalDetalhe({ aberto: true, tipo: 'Despesas', dados: dados.categoriasDespesa })}>
          <div className="obj-header">
            <span className="obj-name"><ArrowDownCircle size={16} color="#ef4444" /> Total Gasto</span>
            <span className="obj-percent" style={{color: '#ef4444'}}>{porcGasto.toFixed(0)}%</span>
          </div>
          <div className="obj-progress-container">
            <div className="obj-progress-fill" style={{ width: `${Math.min(porcGasto, 100)}%`, backgroundColor: '#ef4444' }} />
          </div>
          <div className="obj-footer">
            <span className="obj-real">{formatMoney(dados.gastoReal)}</span>
            <span className="obj-goal">Teto: {formatMoney(dados.metaGasto)}</span>
          </div>
        </div>
      </div>

      {/* EQUILÍBRIO 50-30-20 */}
      <section className="alocacao-503020">
        <h3 className="premium-section-title">Equilíbrio 50-30-20 (Atual)</h3>
        <div className="alocacao-grid-3-col">
          {['essenciais', 'estiloVida', 'prioridades'].map((key) => {
            const label = key === 'essenciais' ? 'Essenciais (50%)' : key === 'estiloVida' ? 'Desejos (30%)' : 'Futuro (20%)';
            const color = key === 'essenciais' ? '#3b82f6' : key === 'estiloVida' ? '#f59e0b' : '#8b5cf6';
            const valor = dados.resumo503020[key].valor;
            const limite = dados.resumo503020[key].limite;
            const porcLocal = limite > 0 ? (valor / limite) * 100 : 0;

            return (
              <div key={key} className="aloc-mini-card">
                <span className="aloc-label">{label}</span>
                <span className="aloc-valor">{formatMoney(valor)}</span>
                <div className="aloc-progress-bg">
                  <div className="aloc-progress-fill" style={{ width: `${Math.min(porcLocal, 100)}%`, backgroundColor: color }} />
                </div>
                <small>Teto: {formatMoney(limite)}</small>
              </div>
            );
          })}
        </div>
      </section>

      {/* OBJETIVOS PESSOAIS */}
      <h3 className="premium-section-title"><TrendingUp size={18} /> Objetivos Ativos</h3>
      <div className="objectives-grid">
        {dados.objetivosPessoais.map(meta => (
          <div key={meta.id} className="objective-card-premium">
            <div className="obj-header">
              <span className="obj-name">{meta.nomeMetaPessoal || meta.nome}</span>
              <span className="obj-percent">{(meta.metaValor > 0 ? (meta.gastoReal/meta.metaValor)*100 : 0).toFixed(0)}%</span>
            </div>
            <div className="obj-progress-container"><div className="obj-progress-fill" style={{ width: `${Math.min((meta.gastoReal/meta.metaValor)*100, 100)}%` }} /></div>
            <div className="obj-footer"><span className="obj-real">{formatMoney(meta.gastoReal)}</span><span className="obj-goal">alvo: {formatMoney(meta.metaValor)}</span></div>
          </div>
        ))}
      </div>

      {/* MODAL DE DETALHES */}
      {modalDetalhe.aberto && (
        <div className="modal-overlay fade-in" onClick={() => setModalDetalhe({ ...modalDetalhe, aberto: false })}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>Detalhes de {modalDetalhe.tipo}</h3>
              <button onClick={() => setModalDetalhe({ ...modalDetalhe, aberto: false })}><X size={20} /></button>
            </div>
            <div className="modal-body">
              {modalDetalhe.tipo === 'Receitas' ? (
                modalDetalhe.dados.map((p, i) => (
                  <div key={i} className="detalhe-item">
                    <span>Provento {i+1}</span>
                    <strong>{formatMoney(p.valor)}</strong>
                  </div>
                ))
              ) : (
                modalDetalhe.dados.map(c => (
                  <div key={c.id} className="detalhe-item">
                    <div className="item-info">
                      <div className="cat-indicator" style={{backgroundColor: c.cor}}></div>
                      <span>{c.nome}</span>
                    </div>
                    <strong>{formatMoney(c.gastoReal)}</strong>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Orcamento;
